@app.route('/cache/clear', methods=['POST'])
def clear_cache():
    data = request.get_json() or {}
    pattern = data.get('pattern', 'cache:*')
    invalidate_cache(pattern)
    return jsonify({'status': 'success', 'message': f'Cache cleared for pattern: {pattern}'})


@app.route('/cache/info', methods=['GET'])
def cache_info():
    cache_keys = redis_cache.keys('*')
    cache_data = {}
    
    for key in cache_keys[:20]:
        ttl = redis_cache.ttl(key)
        cache_data[key.decode()] = {
            'ttl': ttl,
            'exists': True
        }
    
    return jsonify({
        'total_keys': len(cache_keys),
        'sample_keys': cache_data
    })


@app.route('/session/count', methods=['GET'])
def session_count():
    session_keys = redis_client.keys('session:*')
    return jsonify({
        'active_sessions': len(session_keys)
    })


